mapper.select:
SELECT /* CanCustMapper.selectRclCustList */ RCL.CONTRACT_NUM AS CONTRACT_NUM , SUB.SVC_CNTR_NO AS SVC_CNTR_NO , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM , TO_CHAR(TO_DATE(RCL.RCL_DTTM,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS RCL_DTTM , FN_GET_CODENM('MSP0004', RCL.RCL_CODE) AS RCL_RSN , TO_CHAR(TO_DATE(SUBSTR(RCL.CAN_INFO, 0, 14),'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS RCL_CAN_DTTM , FN_GET_CODENM('MSP0012', SUBSTR(RCL.CAN_INFO, 15)) AS RCL_CAN_RSN , DECODE(SUB.SUB_STATUS, 'C', SUBSTR(SUB.SUB_STATUS_DATE,0,8)) AS CAN_DTTM , CASE WHEN SUB.SUB_STATUS = 'C' THEN FN_GET_CODENM('MSP0012', SUB.SUB_STATUS_RSN_CODE) ELSE NULL END AS CAN_RSN , ( SELECT B.DATA_TYPE FROM MSP_JUO_FEATURE_INFO A , MSP_RATE_MST B WHERE A.CONTRACT_NUM = SUB.CONTRACT_NUM AND A.SERVICE_TYPE = 'P' AND A.EVNT_TRTM_DT = ( SELECT MAX(EVNT_TRTM_DT) FROM MSP_JUO_FEATURE_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM AND SERVICE_TYPE = 'P' ) AND A.SOC = B.RATE_CD AND ROWNUM = 1 ) AS DATA_TYPE , NVL(TRIM(SUBSTR(DTL.FST_MODEL_INFO, 21 , 30)), DTL.REQ_USIM_NAME) AS FST_MODEL , DTL.REQ_BUY_TYPE_NM AS REQ_BUY_TYPE_NM , DTL.FST_RATE_CD AS FST_RATE_CD , DTL.FST_RATE_NM AS FST_RATE_NM , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) AS OPEN_AGNT_NM , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , DTL.OPER_TYPE_NM AS OPER_TYPE_NM , PI.BF_COMM_CMPN_NM AS BF_COMM_CMPN_NM , ( SELECT NVL((SELECT NVL(DTL_CD_NM,NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND DTL_CD = NP_COMM_CMPN_ID), (SELECT NVL(DTL_CD_NM,NP_COMM_CMPN_ID) FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'NSC' AND EXPNSN_STR_VAL1 = NP_COMM_CMPN_ID AND USE_YN = 'Y')) FROM MDS_PORTOUT_MST MPM WHERE MPM.CONTRACT_NUM = SUB.CONTRACT_NUM ) AS NP_COMM_CMPN_NM , DTL.SHOP_NM AS SHOP_NM , FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE_NM , DTL.OPEN_MARKET_REFERER AS OPEN_MARKET_REFERER , CASE WHEN DTL.CSTMR_TYPE = 'JP' OR DTL.CSTMR_TYPE = 'PP' THEN 0 ELSE FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(SUB.USER_SSN)) END AS AGE , CASE WHEN DTL.CSTMR_TYPE = 'JP' OR DTL.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), '-', ''), 7, 1) END AS GENDER , SUB.MODEL_NAME AS MODEL_NAME , DTL.LST_RATE_CD AS LST_RATE_CD , DTL.LST_RATE_NM AS LST_RATE_NM , CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS USIM_ORG_NM , FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM , DECODE(SUB.USIM_TYPE, 'E' , 'Y' , 'N') AS ESIM_YN , DTL.FST_ESIM_YN AS FST_ESIM_YN FROM ( SELECT RCL.CONTRACT_NUM , RCL.STRT_DTTM RCL_DTTM , RCL.SUB_STATUS_RSN_CODE RCL_CODE , MAX(CAN.STRT_DTTM||CAN.SUB_STATUS_RSN_CODE) CAN_INFO FROM ( SELECT CONTRACT_NUM , EVNT_CHANGE_DATE AS STRT_DTTM , SUB_STATUS_RSN_CODE FROM MSP_JUO_SUB_INFO_HIST WHERE EVNT_CD = 'RCL' ) RCL , ( SELECT CONTRACT_NUM , EVNT_CHANGE_DATE AS STRT_DTTM , SUB_STATUS_RSN_CODE FROM MSP_JUO_SUB_INFO_HIST WHERE EVNT_CD = 'CAN' ) CAN WHERE RCL.CONTRACT_NUM = CAN.CONTRACT_NUM AND RCL.STRT_DTTM > CAN.STRT_DTTM GROUP BY RCL.CONTRACT_NUM, RCL.STRT_DTTM, RCL.SUB_STATUS_RSN_CODE ) RCL , MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL DTL , MDS_PORTIN_MST PI , NMCP_USIM_BUY_TXN@DL_MCP MSD , MSP_PARTNER_USIM_MST PUM WHERE RCL.CONTRACT_NUM = SUB.CONTRACT_NUM AND SUB.CONTRACT_NUM = DTL.CONTRACT_NUM AND SUB.CONTRACT_NUM = PI.CONTRACT_NUM(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND DTL.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.PPPO = 'PO'
AND RCL.RCL_DTTM BETWEEN #{searchStartDt}||'000000' AND #{searchEndDt}||'235959'
AND SUB.CONTRACT_NUM = #{searchName}
AND SUB.OPEN_AGNT_CD = #{cntpntShopId}
ORDER BY RCL.RCL_DTTM DESC

SELECT TO_CHAR(A.REGST_DTTM ,'YYYY-MM-DD') AS REGST_DTTM, /*등록일자*/ A.CONTRACT_NUM AS CONTRACT_NUM, /*계약번호*/ SUBSTR(B.SUBSCRIBER_NO, 1, 3) || '-' || SUBSTR(B.SUBSCRIBER_NO, 4, 4) || '-' || SUBSTR(B.SUBSCRIBER_NO, 8, 4) AS SUBSCRIBER_NO, /*전화번호*/ DECODE(B.SUB_STATUS,'A', '사용중', 'S', '정지', 'C', '해지') AS SUB_STATUS, /*현재상태*/ CASE WHEN A.TCP_PRGR_STAT_CD = 'EP4' AND A.TCP_RSLT_CD = '0000' THEN '해지완료' WHEN A.REQ_STATUS = 'Y' THEN '요청완료' WHEN A.REQ_STATUS = 'E' THEN '해지실패' WHEN A.REQ_STATUS = 'P' THEN '요청 중' WHEN A.REQ_STATUS = 'N' THEN '요청대기' WHEN A.REQ_STATUS = 'S' THEN '대상제외' ELSE '' END PROC_STATUS, /*처리상태*/ CASE WHEN A.TCP_PRGR_STAT_CD = 'EP4' AND A.TCP_RSLT_CD = '0000' THEN SUBSTR(A.TCP_RSLT_DTTM, 1, 4) || '-' || SUBSTR(A.TCP_RSLT_DTTM, 5, 2) || '-' || SUBSTR(A.TCP_RSLT_DTTM, 7, 2) ELSE '' END TCP_RSLT_DT, /*해지처리일시*/ FN_GET_CODENM('MSP0012', B.SUB_STATUS_RSN_CODE) AS SUB_STATUS_RSN_REASON, /*해지사유*/ NVL2(A.TCP_RSLT_CD, A.TCP_RSLT_CD, A.OSST_RSLT_CD) AS CAN_CODE, /*해지코드*/ NVL2(A.TCP_RSLT_CD, A.TCP_RSLT_MSG, A.OSST_RSLT_MSG) AS CAN_ERROR_MSG, /*해지불가시 사유*/ A.TCP_RSLT_DTTM AS TCP_RSLT_DTTM, /*연동 시간*/ FN_GET_USRNM(A.REQ_ID) AS REQ_NM, /*처리 요청자*/ TO_CHAR(A.PROC_DTTM,'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM /*처리일시*/ FROM MSP_CAN_REQ A, MSP_JUO_SUB_INFO B WHERE TO_CHAR(A.REGST_DTTM, 'YYYYMMDD') BETWEEN #{searchStartDt} AND #{searchEndDt} AND A.CONTRACT_NUM = B.CONTRACT_NUM
AND A.REQ_STATUS = 'Y' AND A.TCP_PRGR_STAT_CD = 'EP4' AND A.TCP_RSLT_CD = '0000'
AND A.REQ_STATUS = #{procStatus} AND (A.TCP_PRGR_STAT_CD IS NULL OR A.TCP_PRGR_STAT_CD != 'EP4' OR A.TCP_RSLT_CD IS NULL OR A.TCP_RSLT_CD != '0000')
AND A.CONTRACT_NUM = #{pSearchName}
AND B.SUBSCRIBER_NO = #{pSearchName}
ORDER BY A.REGST_DTTM DESC

SELECT TO_CHAR(A.REGST_DTTM ,'YYYY-MM-DD') AS REGST_DTTM, /*등록일자*/ A.CONTRACT_NUM AS CONTRACT_NUM, /*계약번호*/ SUBSTR(B.SUBSCRIBER_NO, 1, 3) || '-' || SUBSTR(B.SUBSCRIBER_NO, 4, 4) || '-' || SUBSTR(B.SUBSCRIBER_NO, 8, 4) AS SUBSCRIBER_NO, /*전화번호*/ DECODE(B.SUB_STATUS,'A', '사용중', 'S', '정지', 'C', '해지') AS SUB_STATUS, /*현재상태*/ CASE WHEN A.TCP_PRGR_STAT_CD = 'EP4' AND A.TCP_RSLT_CD = '0000' THEN '해지완료' WHEN A.REQ_STATUS = 'Y' THEN '요청완료' WHEN A.REQ_STATUS = 'E' THEN '해지실패' WHEN A.REQ_STATUS = 'P' THEN '요청 중' WHEN A.REQ_STATUS = 'N' THEN '요청대기' WHEN A.REQ_STATUS = 'S' THEN '대상제외' ELSE '' END PROC_STATUS, /*처리상태*/ CASE WHEN A.TCP_PRGR_STAT_CD = 'EP4' AND A.TCP_RSLT_CD = '0000' THEN SUBSTR(A.TCP_RSLT_DTTM, 1, 4) || '-' || SUBSTR(A.TCP_RSLT_DTTM, 5, 2) || '-' || SUBSTR(A.TCP_RSLT_DTTM, 7, 2) ELSE '' END TCP_RSLT_DT, /*해지처리일시*/ FN_GET_CODENM('MSP0012', B.SUB_STATUS_RSN_CODE) AS SUB_STATUS_RSN_REASON, /*해지사유*/ NVL2(A.TCP_RSLT_CD, A.TCP_RSLT_CD, A.OSST_RSLT_CD) AS CAN_CODE, /*해지코드*/ NVL2(A.TCP_RSLT_CD, A.TCP_RSLT_MSG, A.OSST_RSLT_MSG) AS CAN_ERROR_MSG, /*해지불가시 사유*/ A.TCP_RSLT_DTTM AS TCP_RSLT_DTTM, /*연동 시간*/ FN_GET_USRNM(A.REQ_ID) AS REQ_NM, /*처리 요청자*/ TO_CHAR(A.PROC_DTTM,'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM /*처리일시*/ FROM MSP_CAN_REQ A, MSP_JUO_SUB_INFO B WHERE TO_CHAR(A.REGST_DTTM, 'YYYYMMDD') BETWEEN #{searchStartDt} AND #{searchEndDt} AND A.CONTRACT_NUM = B.CONTRACT_NUM
AND A.REQ_STATUS = 'Y' AND A.TCP_PRGR_STAT_CD = 'EP4' AND A.TCP_RSLT_CD = '0000'
AND A.REQ_STATUS = #{procStatus} AND (A.TCP_PRGR_STAT_CD IS NULL OR A.TCP_PRGR_STAT_CD != 'EP4' OR A.TCP_RSLT_CD IS NULL OR A.TCP_RSLT_CD != '0000')
AND A.CONTRACT_NUM = #{pSearchName}
AND B.SUBSCRIBER_NO = #{pSearchName}
ORDER BY A.REGST_DTTM DESC

mapper.sql:
SELECT A.CUST_REQ_SEQ , A.CONTRACT_NUM , B.SUB_LINK_NAME AS CSTMR_NAME , SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN), 1, 6) AS BIRTH , CASE WHEN C.CSTMR_TYPE = 'JP' OR C.CSTMR_TYPE = 'PP' THEN '' ELSE SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(B.USER_SSN), '-', ''), 7, 1) END GENDER , A.CANCEL_MOBILE_NO , A.RECEIVE_MOBILE_NO , C.LST_RATE_CD , C.LST_RATE_NM , B.MODEL_NAME AS LST_MODEL_NM , B.INTM_SRL_NO AS LST_MODEL_SRL_NUM , CASE WHEN B.SUB_STATUS = 'C' THEN CASE WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') = 0 THEN '당일개통취소' WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 THEN '14일이내해지' WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') < 90 THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS CAN_RSN , TO_CHAR(A.REGST_DTTM,'YYYY-MM-DD HH24:mm:ss') AS REGST_DTTM , B.LST_COM_ACTV_DATE AS OPEN_DT , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM , DECODE(B.SUB_STATUS,'C',SUBSTR(B.SUB_STATUS_DATE, 1 , 8),'') AS CAN_DT , A.PROC_CD , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'CL05' AND DTL_CD = A.PROC_CD) AS PROC_CD_NM , A.MEMO , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM,'YYYY-MM-DD HH24:mm:ss') AS RVISN_DTTM , '해지사유' AS Q1 , A.SURVEY1_TEXT , A.SURVEY2_TEXT , '만족도' AS Q2 , A.SURVEY_SCORE , '직접입력' AS Q3 , A.SURVEY_SUGGESTION , C.RES_NO , A.SCAN_ID AS NEW_SCAN_ID , B.SCAN_ID AS OLD_SCAN_ID FROM MCP_CANCEL_REQUEST@DL_MCP A, MSP_JUO_SUB_INFO B, MSP_REQUEST_DTL C WHERE 1 = 1
AND A.SYS_RDATE_DD BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.CONTRACT_NUM = B.CONTRACT_NUM AND B.CONTRACT_NUM = C.CONTRACT_NUM
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND A.CANCEL_MOBILE_NO = #{searchName}
AND A.RECEIVE_MOBILE_NO = #{searchName}
AND A.PROC_CD = #{searchStatus}
ORDER BY A.REGST_DTTM DESC

mapper.select:
    	/* CanCustMapper.getCanCslFileNum */
		SELECT MAX(FILE_NUMBER) + 1 AS fileNum
		  FROM EMV_SCAN_FILE@DL_MCP
		 WHERE SCAN_ID = #{oldScanId}

mapper.insert:
    	/* CanCustMapper.insertCanCslEmvFile */
		INSERT INTO EMV_SCAN_FILE@DL_MCP
	    ( FILE_ID, SCAN_ID, FILE_NUMBER, FILE_SIZE, FILE_EXT, DOC_ID, MAIN_DOC_CD, USE_YN, ORIGIN_DIR, RGST_DT, RGST_PRSN_ID )
		SELECT FILE_ID, #{oldScanId}, #{fileNum} + FILE_NUMBER, FILE_SIZE, FILE_EXT, DOC_ID, MAIN_DOC_CD, USE_YN, ORIGIN_DIR, RGST_DT, RGST_PRSN_ID
		  FROM EMV_SCAN_FILE@DL_MCP
		 WHERE SCAN_ID = #{newScanId}

mapper.update:
    	/* CanCustMapper.updateCanCslEmvFileMst */
		UPDATE EMV_SCAN_MST@DL_MCP
		   SET SCAN_FILE_CNT = #{maxFileCnt}
		       , MDFY_PRSN_ID =  #{sessionUserId, jdbcType=VARCHAR}
		       , MDFY_DT = SYSDATE
		 WHERE SCAN_ID = #{oldScanId}

    	/* CanCustMapper.updateCanCslProcCd */
		UPDATE MCP_CANCEL_REQUEST@DL_MCP
		   SET MEMO = #{memo}
		       , PROC_CD = #{procCd}
		       , RVISN_ID =  #{sessionUserId, jdbcType=VARCHAR}
		       , RVISN_DTTM = SYSDATE
		 WHERE CUST_REQ_SEQ = #{custReqSeq}
		 AND PROC_CD != 'CP'
